#include <stdio.h>
#include <string.h>

void print_time(int sec) {
    int h = sec / 3600;
    int m = (sec % 3600) / 60;
    int s = sec % 60;
    printf("%02d:%02d:%02d
", h, m, s);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, Q;
        scanf("%d", &N);
        scanf("%d", &Q);
        char cmd[10];
        int sec = N;
        for (int i = 0; i < Q; ++i) {
            scanf("%s", cmd);
            if (strcmp(cmd, "exit") == 0) {
                // skip remaining commands of this test case
                for (int j = i + 1; j < Q; ++j) scanf("%*s");
                break;
            }
            if (strcmp(cmd, "tick") == 0) {
                if (sec > 0) sec--;
                print_time(sec);
            }
        }
    }
    return 0;
}

