    cin.tie(nullptr);
    int T;
    if(!(cin >> T)) return 0;
    while (T--) {
        int N, Q;
        cin >> N >> Q;
        string cmd;
        int sec = N;
        for (int i = 0; i < Q; ++i) {
            cin >> cmd;
            if (cmd == "exit") {
                // skip remaining commands
                for (int j = i + 1; j < Q; ++j) cin >> cmd;
                break;
            }
            if (cmd == "tick") {
                if (sec > 0) --sec;
                print_time(sec);
            }
        }
    }
    return 0;
}

