#!/usr/bin/env python3
import sys

def fmt(sec: int) -> str:
    h = sec // 3600
    m = (sec % 3600) // 60
    s = sec % 60
    return f"{h:02d}:{m:02d}:{s:02d}"

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        Q = int(next(it))
        sec = N
        for i in range(Q):
            cmd = next(it).strip()
            if cmd == "exit":
                # skip remaining commands of this test case
                for _ in range(i + 1, Q):
                    next(it, None)
                break
            if cmd == "tick":
                if sec > 0:
                    sec -= 1
                out.append(fmt(sec))
    sys.stdout.write("
".join(out))

if __name__ == "__main__":
    main()

